const ANIMATIONS_BY_OBJECT = new Map<string, SceneKeyframe[]>();
for (const keyframe of DATA.keyframes) {
  const entries = ANIMATIONS_BY_OBJECT.get(keyframe.object_id) ?? [];
  entries.push(keyframe);
  ANIMATIONS_BY_OBJECT.set(keyframe.object_id, entries);
}
for (const entries of ANIMATIONS_BY_OBJECT.values()) {
  entries.sort((a, b) => a.start_f - b.start_f || a.end_f - b.end_f || a.kind.localeCompare(b.kind));
}

type ObjectState = {
  draw: number;
  highlight: number;
  opacity: number;
  scale: number;
  translateY: number;
  visible: boolean;
};

const clamp = (value: number, min: number, max: number): number => {
  return Math.min(max, Math.max(min, value));
};

const ease = (name: Easing, value: number): number => {
  const t = clamp(value, 0, 1);
  if (name === "linear") {
    return t;
  }
  if (name === "spring") {
    return 1 - Math.cos(t * Math.PI * 4) * Math.exp(-6 * t);
  }
  return t * t * (3 - 2 * t);
};

const stateFor = (objectId: string, frame: number, fps: number): ObjectState => {
  const animations = ANIMATIONS_BY_OBJECT.get(objectId) ?? [];
  if (animations.length === 0) {
    return {draw: 1, highlight: 0, opacity: 1, scale: 1, translateY: 0, visible: true};
  }
  let visible = false;
  let opacity = 0;
  let scale = 0.96;
  let translateY = 24;
  let highlight = 0;
  let draw = 0;
  for (const keyframe of animations) {
    if (frame < keyframe.start_f) {
      continue;
    }
    const span = Math.max(1, keyframe.end_f - keyframe.start_f);
    const progress = ease(keyframe.easing, (frame - keyframe.start_f) / span);
    if (keyframe.kind === "fade_in") {
      visible = true;
      opacity = Math.max(opacity, progress);
      scale = 0.96 + progress * 0.04;
      translateY = (1 - progress) * 24;
      continue;
    }
    if (keyframe.kind === "draw") {
      visible = true;
      opacity = 1;
      scale = 1;
      translateY = 0;
      draw = frame >= keyframe.end_f ? 1 : progress;
      continue;
    }
    if (keyframe.kind === "highlight") {
      visible = true;
      opacity = 1;
      scale = 1 + 0.02 * progress;
      translateY = 0;
      highlight = frame >= keyframe.end_f ? 0 : progress;
      continue;
    }
    if (keyframe.kind === "fade_out") {
      visible = frame < keyframe.end_f;
      opacity = frame >= keyframe.end_f ? 0 : 1 - progress;
      scale = 1;
      translateY = 0;
    }
  }
  if (visible && opacity <= 0) {
    opacity = 1;
  }
  if (draw <= 0 && visible) {
    draw = 1;
  }
  if (!visible) {
    const entry = spring({frame, fps, config: {damping: 18}});
    return {draw: 0, highlight: 0, opacity: 0, scale: 0.96 + entry * 0.04, translateY: 24, visible: false};
  }
  return {draw, highlight, opacity: clamp(opacity, 0, 1), scale, translateY, visible};
};

const captionForFrame = (frame: number): string => {
  for (const caption of DATA.captions) {
    if (frame >= caption.start_f && frame < caption.end_f) {
      return caption.text;
    }
  }
  return "";
};

const objectStyle = (object: SceneObject, state: ObjectState): React.CSSProperties => ({
  position: "absolute",
  left: object.x,
  top: object.y,
  width: object.w,
  height: object.h,
  zIndex: object.z,
  opacity: state.opacity,
  transform: `translateY(${state.translateY}px) scale(${state.scale})`,
  transformOrigin: "center center",
  filter: state.highlight > 0 ? `drop-shadow(0 0 ${12 + 12 * state.highlight}px rgba(251, 191, 36, ${0.2 + state.highlight * 0.35}))` : undefined,
  boxSizing: "border-box",
  pointerEvents: "none",
});

const arrowStrokeWidth = (object: SceneObject): number => Math.max(object.h, 2);

const ArrowObject: React.FC<{object: SceneObject; state: ObjectState}> = ({object, state}) => {
  const stroke = object.style.color ?? "#E5E7EB";
  const lineWidth = object.w * clamp(state.draw, 0, 1);
  const headStart = Math.max(0, lineWidth - 12);
  const centerY = object.h / 2;
  return (
    <svg viewBox={`0 0 ${object.w} ${object.h}`} preserveAspectRatio="none" aria-hidden="true" style={{display: "block", width: "100%", height: "100%", overflow: "visible"}}>
      <line x1={0} y1={centerY} x2={Math.max(0, lineWidth - 12)} y2={centerY} stroke={stroke} strokeWidth={arrowStrokeWidth(object)} strokeLinecap="round" />
      {lineWidth > 0 ? <path d={`M ${headStart} 0 L ${lineWidth} ${centerY} L ${headStart} ${object.h} Z`} fill={stroke} /> : null}
    </svg>
  );
};

const renderObject = (object: SceneObject, state: ObjectState): React.ReactNode => {
  if (!state.visible && state.opacity <= 0) {
    return null;
  }
  const baseStyle = objectStyle(object, state);
  if (object.primitive === "rect") {
    return <div style={{...baseStyle, borderRadius: 18, border: `2px solid ${object.style.stroke_color ?? "#E5E7EB"}`, background: `linear-gradient(180deg, color-mix(in srgb, ${object.style.fill_color ?? "#1D4ED8"} 82%, white 18%), ${object.style.fill_color ?? "#1D4ED8"})`, boxShadow: "0 10px 28px rgba(11, 16, 32, 0.45)"}} />;
  }
  if (object.primitive === "arrow") {
    return <div style={baseStyle}><ArrowObject object={object} state={state} /></div>;
  }
  if (object.primitive === "code") {
    return (
      <div style={{...baseStyle, display: "grid", placeItems: "center", color: object.style.color ?? "#E5E7EB"}}>
        <pre style={{margin: 0, width: "100%", height: "100%", display: "grid", placeItems: "center", padding: "14px 18px", borderRadius: 14, background: "rgba(15, 23, 42, 0.78)", border: "1px solid rgba(148, 163, 184, 0.28)", boxShadow: "0 10px 28px rgba(11, 16, 32, 0.45)", fontFamily: "ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace", fontSize: 20, fontWeight: 600, lineHeight: 1.3}}>{object.text}</pre>
      </div>
    );
  }
  if (object.primitive === "formula") {
    return (
      <div style={{...baseStyle, display: "grid", placeItems: "center", color: object.style.color ?? "#E5E7EB"}}>
        <div style={{width: "100%", height: "100%", display: "grid", placeItems: "center", borderRadius: 16, background: "rgba(15, 23, 42, 0.42)", border: "1px solid rgba(229, 231, 235, 0.24)", fontFamily: '"Times New Roman", Georgia, serif', fontSize: 26, fontStyle: "italic", fontWeight: 600, lineHeight: 1.2}}>{object.text}</div>
      </div>
    );
  }
  if (object.primitive === "icon") {
    return (
      <div style={{...baseStyle, display: "grid", placeItems: "center", color: object.style.color ?? "#E5E7EB"}}>
        <div style={{width: "100%", height: "100%", display: "grid", placeItems: "center", borderRadius: 999, background: `radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.2), transparent 35%), ${object.style.fill_color ?? "#0891B2"}`, border: `2px solid ${object.style.stroke_color ?? "rgba(229, 231, 235, 0.4)"}`, boxShadow: "0 10px 28px rgba(11, 16, 32, 0.45)", fontSize: 34, fontWeight: 700}}>{object.glyph}</div>
      </div>
    );
  }
  const ts = object.textStyle!;
  return (
    <div style={{...baseStyle, display: "grid", placeItems: "center"}}>
      <span style={{color: ts.color, fontFamily: ts.fontFamily, fontSize: ts.fontSize, fontWeight: ts.fontWeight, letterSpacing: "-0.02em", lineHeight: 1.1, textAlign: ts.textAlign as React.CSSProperties["textAlign"], width: "100%"}}>{object.text}</span>
    </div>
  );
};

export const VirocScene: React.FC = () => {
  const frame = useCurrentFrame();
  const {fps, width, height} = useVideoConfig();
  const caption = captionForFrame(frame);
  return (
    <AbsoluteFill style={{backgroundColor: DATA.background, color: "#E5E7EB", fontFamily: "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif"}}>
      <AbsoluteFill style={{display: "grid", placeItems: "center"}}>
        <div style={{position: "relative", width, height, overflow: "hidden", background: "linear-gradient(180deg, rgba(15, 23, 42, 0.96), rgba(11, 16, 32, 1))", boxShadow: "0 24px 64px rgba(0, 0, 0, 0.35)", isolation: "isolate"}}>
          {DATA.objects.map((object) => renderObject(object, stateFor(object.id, frame, fps)))}
          <div style={{position: "absolute", left: 96, right: 96, bottom: 48, minHeight: 72, display: "grid", alignItems: "center", justifyItems: "center", padding: "14px 18px", borderRadius: 18, background: "rgba(11, 16, 32, 0.72)", border: "1px solid rgba(229, 231, 235, 0.14)", fontSize: 28, fontWeight: 500, lineHeight: 1.25, letterSpacing: "-0.01em", textAlign: "center", opacity: caption ? 1 : 0}}>
            {caption}
          </div>
        </div>
      </AbsoluteFill>
    </AbsoluteFill>
  );
};
